local R=loadstring(game:HttpGet('https://raw.githubusercontent.com/SiriusSoftwareLtd/Rayfield/main/source.lua'))() local W=R:CreateWindow({Name="N0XY MASTER ENGINE 💀 (v7)",LoadingTitle="Загрузка N0XY CORE...",LoadingSubtitle="by N0XY",ConfigurationSaving={Enabled=false}}) local P=game:GetService("Players") local LP=P.LocalPlayer local RS=game:GetService("RunService") local L=game:GetService("Lighting") local flying,flySpeed,noclip,antiFling,wsVal,jpVal,targetName,loopFling,orbit,kAu,jrk,spin,szR=false,50,false,false,16,50,"",false,false,false,false,false,false _G.Aim,_G.AutoClick=false,false local ST={Space="rbxassetid://159454286",Fire="rbxassetid://1760874933",Night="rbxassetid://12128522303"} local musicId="" local function getT() for _,p in pairs(P:GetPlayers()) do if p.Name:lower():sub(1,#targetName)==targetName or p.DisplayName:lower():sub(1,#targetName)==targetName then return p end end return nil end local function setAnim(id) pcall(function() local c=LP.Character if c and c:FindFirstChild("Animate") then local s={"walk","run","jump","idle"} for _,st in pairs(s) do local mo=c.Animate:FindFirstChild(st) or c.Animate:FindFirstChild(st:sub(1,1):upper()..st:sub(2).."Anim") if mo then for _,an in pairs(mo:GetChildren()) do if an:IsA("Animation") then an.AnimationId="rbxassetid://"..id end end end end local h=c:FindFirstChildOfClass("Humanoid") if h then h:ChangeState(Enum.HumanoidStateType.Inaction) end end end) end local T1=W:CreateTab("Главная & PvP ⚔️",0) local T2=W:CreateTab("Мир & Небо 🌌",0) local T3=W:CreateTab("Троллинг Цели 😈",0) local T4=W:CreateTab("Хаос Сервера 💥",0) local T5=W:CreateTab("Анимации 🎭",0) local T6=W:CreateTab("Радио 🎵",0) local FlyC T1:CreateToggle({Name="Fly (Полёт)",CurrentValue=false,Callback=function(v) flying=v if flying then local C=LP.Character or LP.CharacterAdded:Wait() local H=C:WaitForChild("HumanoidRootPart") local Hum=C:WaitForChild("Humanoid") local Cam=workspace.CurrentCamera Hum.PlatformStand=true FlyC=RS.Heartbeat:Connect(function(dt) if not flying or not C or not H.Parent then if FlyC then FlyC:Disconnect() end return end local md=Hum.MoveDirection if md.Magnitude>0 then local fd=(Cam.CFrame*CFrame.new(Vector3.new(md.X,0,md.Z))).LookVector H.CFrame=H.CFrame+(fd*(flySpeed*dt)) end H.Velocity=Vector3.new(0,0,0) end) else if FlyC then FlyC:Disconnect() end pcall(function() LP.Character.Humanoid.PlatformStand=false end) end end}) T1:CreateSlider({Name="WalkSpeed (Скорость)",Range={16,250},Increment=5,CurrentValue=16,Callback=function(v) wsVal=v end}) T1:CreateSlider({Name="JumpPower (Прыжок)",Range={50,300},Increment=5,CurrentValue=50,Callback=function(v) jpVal=v end}) T1:CreateToggle({Name="Noclip (Сквозь стены)",CurrentValue=false,Callback=function(v) noclip=v end}) T1:CreateToggle({Name="Anti-Fling (Защита)",CurrentValue=false,Callback=function(v) antiFling=v end}) T1:CreateToggle({Name="Aim-Lock (Наводка)",CurrentValue=false,Callback=function(v) _G.Aim=v end}) T1:CreateToggle({Name="Auto-Clicker (Авто-удар)",CurrentValue=false,Callback=function(v) _G.AutoClick=v end}) T2:CreateDropdown({Name="Выбрать небо (Skybox)",Options={"Space","Fire","Night"},Callback=function(o) local s=L:FindFirstChildOfClass("Sky") or Instance.new("Sky",L) s.SkyboxBk=ST[o] s.SkyboxDn=ST[o] s.SkyboxFt=ST[o] s.SkyboxLf=ST[o] s.SkyboxRt=ST[o] s.SkyboxUp=ST[o] end}) T2:CreateButton({Name="Fog Disable",Callback=function() L.FogEnd=100000 end}) T3:CreateInput({Name="Ник жертвы",PlaceholderText="Имя...",Callback=function(t) targetName=t:lower() end}) T3:CreateButton({Name="Посадить в РЕАЛЬНУЮ клетку! 🧱",Callback=function() local p=getT() if p and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then local tH=p.Character.HumanoidRootPart if workspace:FindFirstChild("RealCage_"..p.Name) then workspace["RealCage_"..p.Name]:Destroy() end local CM=Instance.new("Model",workspace) CM.Name="RealCage_"..p.Name local fl=Instance.new("Part",CM) fl.Size=Vector3.new(8,0.5,8) fl.CFrame=tH.CFrame*CFrame.new(0,-3.5,0) fl.Anchored=true local rf=Instance.new("Part",CM) rf.Size=Vector3.new(8,0.5,8) rf.CFrame=tH.CFrame*CFrame.new(0,4.5,0) rf.Anchored=true local function sb(o) local b=Instance.new("Part",CM) b.Size=Vector3.new(0.2,8,0.2) b.CFrame=tH.CFrame*o b.Anchored=true b.Material=Enum.Material.Iron end for k=-3.5,3.5,1.2 do sb(CFrame.new(k,0.5,-3.5)) sb(CFrame.new(k,0.5,3.5)) sb(CFrame.new(-3.5,0.5,k)) sb(CFrame.new(3.5,0.5,k)) end end end}) T3:CreateToggle({Name="Loop Fling",CurrentValue=false,Callback=function(v) loopFling=v task.spawn(function() while loopFling do pcall(function() local p=getT() if p and p.Character then local mH=LP.Character.HumanoidRootPart mH.CFrame=p.Character.HumanoidRootPart.CFrame*CFrame.new(math.random(-1,1),0,math.random(-1,1)) mH.Velocity=Vector3.new(7000,7000,7000) mH.RotVelocity=Vector3.new(7000,7000,7000) end end) task.wait(0.01) end end) end}) T4:CreateToggle({Name="Kill Aura",CurrentValue=false,Callback=function(v) kAu=v task.spawn(function() while kAu do pcall(function() local mH=LP.Character.HumanoidRootPart for _,p in pairs(P:GetPlayers()) do if p~=LP and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then if (mH.Position-p.Character.HumanoidRootPart.Position).Magnitude<15 then local tl=LP.Character:FindFirstChildOfClass("Tool") if tl then tl:Activate() end end end end end) task.wait(0.1) end end) end}) T5:CreateButton({Name="Mage Animation (Маг)",Callback=function() setAnim("707827244") end}) T5:CreateButton({Name="Ninja Animation (Ниндзя)",Callback=function() setAnim("616111377") end}) T6:CreateInput({Name="ID Музыки",PlaceholderText="ID...",Callback=function(t) musicId=t end}) T6:CreateButton({Name="Включить музыку 🔊",Callback=function() pcall(function() local s=workspace:FindFirstChild("N0XY_Radio") or Instance.new("Sound",workspace) s.Name="N0XY_Radio" s.SoundId="rbxassetid://"..musicId s.Volume=2 s.Looped=true s:Play() end) end}) T6:CreateButton({Name="Остановить 🔇",Callback=function() pcall(function() local s=workspace:FindFirstChild("N0XY_Radio") if s then s:Stop() s:Destroy() end end) end}) RS.RenderStepped:Connect(function() if _G.Aim then local nr=nil local di=math.huge for _,p in pairs(P:GetPlayers()) do if p~=LP and p.Character and p.Character:FindFirstChild("Head") then local d=(p.Character.Head.Position-LP.Character.Head.Position).Magnitude if d<di then nr=p.Character.Head di=d end end end if nr then workspace.CurrentCamera.CFrame=CFrame.new(workspace.CurrentCamera.CFrame.Position,nr.Position) end end if _G.AutoClick then local tl=LP.Character:FindFirstChildOfClass("Tool") if tl then tl:Activate() end end end) RS.Stepped:Connect(function() if noclip and LP.Character then for _,pt in pairs(LP.Character:GetDescendants()) do if pt:IsA("BasePart") then pt.CanCollide=false end end end if antiFling and LP.Character then pcall(function() for _,pt in pairs(LP.Character:GetDescendants()) do if pt:IsA("BasePart") then pt.Velocity=Vector3.new(0,0,0) pt.RotVelocity=Vector3.new(0,0,0) end end end) end end) task.spawn(function() while true do pcall(function() if LP.Character and LP.Character:FindFirstChild("Humanoid") then local hu=LP.Character.Humanoid if hu.WalkSpeed~=wsVal and not flying then hu.WalkSpeed=wsVal end if hu.JumpPower~=jpVal then hu.UseJumpPower=true hu.JumpPower=jpVal end end end) task.wait(0.1) end end)
